hints.text:
double temp = Plc.ReadHoldingRegister(100) / 10.0;
if (temp < 30)
    Print($"{temp:F1}°C 正常");
else if (temp <= 35)
{
    Plc.WriteHoldingRegister(200, 50);
    Print($"{temp:F1}°C 黄色预警，降功率至50%");
}
else
{
    Plc.WriteCoil(10, true);
    Print($"{temp:F1}°C 红色停机！");
}
